package VehicleModel {
    /**
    * Basic vehicle model demonstrating SysML v2.0 syntax
    * including parts, attributes, ports, constraints, and requirements
    */

    part def Vehicle {
        part engine : Engine;
        part transmission : Transmission;
        part wheels : Wheel[4];
        port powerOut : PowerPort;
        port dataPort : DataPort;

        attribute mass : Real;
        attribute maxSpeed : Real;
        attribute acceleration0To60 : Real;
        attribute brakingDistance60To0 : Real;
        attribute availability : Real;
        attribute meanTimeBetweenFailures : Real;
        attribute meanTimeToRepair : Real;
        attribute diagnosticCoverage : Real;
        attribute supportedChargeStandards : Integer;

        constraint massConstraint {
            mass < 2000.0
        }

        constraint speedConstraint {
            maxSpeed > 60.0
        }
    }

    part def Engine {
        attribute power : Real;
        attribute mass : Real;
        attribute displacement : Real;
        port powerPort : PowerPort;

        constraint powerMassRatio {
            power / mass > 0.1
        }
    }

    part def Transmission :> Subsystem {
        attribute gearRatio : Real;
        attribute efficiency : Real;

        constraint efficiencyConstraint {
            efficiency >= 0.85 and efficiency <= 1.0
        }
    }

    part def Wheel {
        attribute diameter : Real;
        attribute width : Real;

        constraint sizeConstraint {
            diameter >= 14.0 and diameter <= 22.0
        }
    }

    part def Subsystem {
        attribute mass : Real;
        attribute cost : Real;
    }

    port def PowerPort {
        attribute voltage : Real;
        attribute current : Real;

        constraint powerLimit {
            voltage * current <= 1000.0
        }
    }

    port def DataPort {
        attribute bandwidthMbps : Real;
        attribute protocolVersion : Real;

        constraint dataPortConstraint {
            bandwidthMbps >= 100.0
        }
    }

    requirement def VehicleCapabilityReq {
        doc /* The vehicle shall provide transportation capability for a licensed driver in normal road operation. */

        subject vehicle : Vehicle;
    }

    requirement def PerformanceReq {
        doc /* The vehicle shall accelerate from 0 to 60 mph in less than 6 seconds. */

        subject vehicle : Vehicle;

        require constraint {
            vehicle.acceleration0To60 < 6.0
        }
    }

    requirement def SafetyReq {
        doc /* The vehicle shall provide safe braking performance during normal road operation. */

        subject vehicle : Vehicle;

        require constraint {
            vehicle.brakingDistance60To0 <= 40.0
        }
    }

    requirement def ReliabilityReq {
        doc /* The vehicle shall achieve operational reliability sufficient for consumer road use. */

        subject vehicle : Vehicle;

        require constraint {
            vehicle.meanTimeBetweenFailures >= 1000.0 and vehicle.availability >= 0.95
        }
    }

    requirement def MaintainabilityReq {
        doc /* The vehicle shall support maintainable operation through timely repair and onboard fault isolation. */

        subject vehicle : Vehicle;

        require constraint {
            vehicle.meanTimeToRepair <= 2.0 and vehicle.diagnosticCoverage >= 0.90
        }
    }

    requirement def InteroperabilityReq {
        doc /* The vehicle shall interoperate with external charging and diagnostic infrastructure using standardized interfaces. */

        subject vehicle : Vehicle;

        require constraint {
            vehicle.supportedChargeStandards >= 2 and vehicle.dataPort.bandwidthMbps >= 100.0
        }
    }

    requirement def DerivedPowerReq {
        doc /* Derived from vehicle acceleration performance, the propulsion system shall provide at least 300 kW of engine power. */

        subject vehicle : Vehicle;

        derivedReq PerformanceReq;

        require constraint {
            vehicle.engine.power >= 300.0
        }
    }

    requirement def DerivedTransmissionEfficiencyReq {
        doc /* Derived from vehicle acceleration performance, the transmission efficiency shall be at least 0.90. */

        subject vehicle : Vehicle;

        derivedReq PerformanceReq;

        require constraint {
            vehicle.transmission.efficiency >= 0.90
        }
    }

    requirement def DerivedBrakeLoadReq {
        doc /* Derived from braking safety, the vehicle mass supported per wheel shall not exceed 500 units. */

        subject vehicle : Vehicle;

        derivedReq SafetyReq;

        require constraint {
            vehicle.mass / vehicle.wheels.size <= 500.0
        }
    }

    requirement def DerivedDiagnosticsReq {
        doc /* Derived from maintainability, the vehicle shall provide onboard diagnostics with at least 90 percent diagnostic coverage. */

        subject vehicle : Vehicle;

        derivedReq MaintainabilityReq;

        require constraint {
            vehicle.diagnosticCoverage >= 0.90
        }
    }

    requirement def DerivedChargingInterfaceReq {
        doc /* Derived from interoperability, the vehicle shall support at least two external charging interface standards. */

        subject vehicle : Vehicle;

        derivedReq InteroperabilityReq;

        require constraint {
            vehicle.supportedChargeStandards >= 2
        }
    }

    requirement PerformanceRequirement : PerformanceReq;
    requirement SafetyRequirement : SafetyReq;
    requirement ReliabilityRequirement : ReliabilityReq;
    requirement MaintainabilityRequirement : MaintainabilityReq;
    requirement InteroperabilityRequirement : InteroperabilityReq;
    requirement DerivedPowerRequirement : DerivedPowerReq;
    requirement DerivedTransmissionEfficiencyRequirement : DerivedTransmissionEfficiencyReq;
    requirement DerivedBrakeLoadRequirement : DerivedBrakeLoadReq;
    requirement DerivedDiagnosticsRequirement : DerivedDiagnosticsReq;
    requirement DerivedChargingInterfaceRequirement : DerivedChargingInterfaceReq;

    refine DerivedPowerRequirement to PerformanceRequirement;
    refine DerivedTransmissionEfficiencyRequirement to PerformanceRequirement;
    refine DerivedBrakeLoadRequirement to SafetyRequirement;
    refine DerivedDiagnosticsRequirement to MaintainabilityRequirement;
    refine DerivedChargingInterfaceRequirement to InteroperabilityRequirement;

    verification def AccelerationTest {
        doc /* Test the vehicle acceleration time from 0 to 60 mph. */
    }

    verification def BrakingTest {
        doc /* Test the vehicle braking distance from 60 mph to 0. */
    }

    verification def ReliabilityAnalysis {
        doc /* Analyze fleet reliability metrics including MTBF and availability. */
    }

    verification def MaintainabilityInspection {
        doc /* Inspect serviceability and confirm repair-time and diagnostic coverage objectives. */
    }

    verification def InteroperabilityTest {
        doc /* Test compatibility with supported charging and diagnostic infrastructure. */
    }

    verification accelVerification : AccelerationTest;
    verification brakingVerification : BrakingTest;
    verification reliabilityVerification : ReliabilityAnalysis;
    verification maintainabilityVerification : MaintainabilityInspection;
    verification interoperabilityVerification : InteroperabilityTest;

    verify PerformanceRequirement by accelVerification;
    verify DerivedPowerRequirement by accelVerification;
    verify DerivedTransmissionEfficiencyRequirement by accelVerification;
    verify SafetyRequirement by brakingVerification;
    verify DerivedBrakeLoadRequirement by brakingVerification;
    verify ReliabilityRequirement by reliabilityVerification;
    verify MaintainabilityRequirement by maintainabilityVerification;
    verify DerivedDiagnosticsRequirement by maintainabilityVerification;
    verify InteroperabilityRequirement by interoperabilityVerification;
    verify DerivedChargingInterfaceRequirement by interoperabilityVerification;

    use case def DriveCar {
        actor driver : Driver;
        subject vehicle : Vehicle;

        objective {
            doc /* Successfully operate the vehicle from point A to point B */
        }
    }

    part def Driver {
        attribute experience : Real;
        attribute licenseValid : Boolean;
    }

    // Example vehicle instances
    part myCar : Vehicle {
        :>> engine {
            :>> power = 250.0;
            :>> mass = 150.0;
            :>> displacement = 2.0;
        }

        :>> transmission {
            :>> gearRatio = 3.5;
            :>> efficiency = 0.92;
        }

        :>> dataPort {
            :>> bandwidthMbps = 1000.0;
            :>> protocolVersion = 2.0;
        }

        :>> mass = 1500.0;
        :>> maxSpeed = 120.0;
        :>> acceleration0To60 = 6.5;
        :>> brakingDistance60To0 = 38.0;
        :>> availability = 0.97;
        :>> meanTimeBetweenFailures = 1200.0;
        :>> meanTimeToRepair = 1.5;
        :>> diagnosticCoverage = 0.93;
        :>> supportedChargeStandards = 2;
    }
}

